import{app}from"./firebase.min.js";import{getAuth,createUserWithEmailAndPassword,signInWithEmailAndPassword}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-auth.js";import{getFirestore,doc,setDoc}from"https://www.gstatic.com/firebasejs/12.1.0/firebase-firestore.js";const auth=getAuth(app),db=getFirestore(app);function showPopup(e,t=4e3,s=null){const o=document.getElementById("auth-popup");o.textContent=e,o.classList.add("show"),setTimeout(()=>{o.classList.remove("show"),s&&(window.location.href=s)},t)}document.getElementById("auth-form").addEventListener("submit",async e=>{e.preventDefault();const t=document.getElementById("email").value.trim(),s=document.getElementById("password").value.trim(),o=document.getElementById("confirm-password")?.value.trim(),a=document.getElementById("nationality")?.value.trim(),i="Sign Up"===document.getElementById("submit-btn").textContent;try{if(i){if(s!==o)return void showPopup("⚡ Passwords do not match. Please try again.",4e3);if(!a)return void showPopup("🌍 Please select your nationality.",4e3);const e=(await createUserWithEmailAndPassword(auth,t,s)).user;await setDoc(doc(db,"users",e.uid),{uid:e.uid,email:e.email,name:e.displayName||"Anonymous User",photoURL:e.photoURL||"default-avatar.png",nationality:a,createdAt:(new Date).toISOString(),authProvider:"email"}),sessionStorage.setItem("userUID",e.uid),sessionStorage.setItem("userEmail",e.email),localStorage.setItem("userUID",e.uid),localStorage.setItem("userEmail",e.email),localStorage.setItem("userNationality",a),showPopup("🤖 Signup successful! Welcome to VeriHuman.",4e3,"index.html")}else{const e=(await signInWithEmailAndPassword(auth,t,s)).user;sessionStorage.setItem("userUID",e.uid),sessionStorage.setItem("userEmail",e.email),showPopup("🤖 Login successful! Access granted.",4e3,"index.html")}}catch(e){showPopup(`⚠️ ${e.message}`,4e3),console.error(e)}});